INSERT INTO `chat_message` VALUES (1,1,3,'ENTERPRISE','你好！感谢你投递我们的岗位，看了你的简历很不错哦~','TEXT',1,'2026-03-06 09:00:00'),(2,1,105,'STUDENT','谢谢HR！我对这个岗位很感兴趣，请问具体工作内容是什么呢？','TEXT',1,'2026-03-06 09:05:00'),(3,1,3,'ENTERPRISE','主要负责后端服务开发，用Golang写微服务。团队氛围很好，有大牛带~','TEXT',1,'2026-03-06 09:10:00'),(4,1,105,'STUDENT','太棒了！我有Go语言的项目经验。请问实习时间是怎么安排的？','TEXT',1,'2026-03-06 09:15:00'),(5,1,3,'ENTERPRISE','暑期6-8月全职，可以提前到也行。方便的话可以约个电话面试聊聊？','TEXT',1,'2026-03-06 09:20:00'),(6,2,4,'ENTERPRISE','你好同学，看到你对前端开发岗位感兴趣！','TEXT',1,'2026-03-06 10:00:00'),(7,2,105,'STUDENT','是的！我熟悉Vue3和React，有独立完成项目的经验。','TEXT',1,'2026-03-06 10:05:00'),(8,2,4,'ENTERPRISE','很好，我们目前主要技术栈是Vue3+TypeScript，你可以先了解下。周三下午有空面试吗？','TEXT',1,'2026-03-06 10:10:00'),(9,3,5,'ENTERPRISE','同学你好，你投递了产品经理训练营，请问你之前有产品相关实习经验吗？','TEXT',1,'2026-03-06 11:00:00'),(10,3,106,'STUDENT','有的，我之前在一家创业公司做过3个月的产品助理，主要负责需求分析和原型设计。','TEXT',0,'2026-03-06 11:05:00'),(11,4,6,'ENTERPRISE','你好！看到你的AI算法经历很亮眼。方便聊聊你做的大模型相关项目吗？','TEXT',1,'2026-03-06 12:00:00'),(12,5,7,'ENTERPRISE','你好！欢迎投递商业分析师岗位。我们对候选人的数据分析能力要求较高哦','TEXT',1,'2026-03-06 13:00:00'),(13,5,107,'STUDENT','明白！我精通Python和SQL数据分析，之前做过一个消费行业的行研报告，可以分享给您看看。','TEXT',0,'2026-03-06 13:05:00'),(14,1,105,'STUDENT','你好','TEXT',0,'2026-03-07 13:39:59'),(15,1,105,'STUDENT','你是说','TEXT',0,'2026-03-07 13:40:06'),(16,1,105,'STUDENT','已发送简历，请查收','RESUME',0,'2026-03-07 13:40:18'),(17,166,105,'STUDENT','{\"name\":\"30-O-b-Glucosylation of nucleoside analogues using a promiscuous bacterial glycosyltransferase†.pdf\",\"size\":\"1326.7 KB\"}','FILE',0,'2026-03-07 13:45:16');
