DROP TABLE IF EXISTS `job_position`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `job_position` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `enterprise_id` bigint NOT NULL COMMENT 'FK to enterprise_info',
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Job title',
  `category_id` bigint DEFAULT NULL COMMENT 'FK to job_category',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT 'Job description',
  `requirements` text COLLATE utf8mb4_unicode_ci COMMENT 'Job requirements',
  `skills_required` json DEFAULT NULL COMMENT 'Required skills as JSON array',
  `salary_min` decimal(10,2) DEFAULT NULL COMMENT 'Min salary (per hour)',
  `salary_max` decimal(10,2) DEFAULT NULL COMMENT 'Max salary (per hour)',
  `work_location` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Work location',
  `work_schedule` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Work schedule description',
  `headcount` int DEFAULT '1' COMMENT 'Number of positions',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'OPEN' COMMENT 'OPEN, CLOSED, DRAFT',
  `view_count` int DEFAULT '0' COMMENT 'View count',
  `apply_count` int DEFAULT '0' COMMENT 'Application count',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `education_requirement` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `duration_requirement` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `job_tags` json DEFAULT NULL,
  `job_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT '综合' COMMENT 'Job type/nature',
  PRIMARY KEY (`id`),
  KEY `enterprise_id` (`enterprise_id`),
  KEY `idx_category` (`category_id`),
  KEY `idx_status` (`status`),
  KEY `idx_created` (`created_at` DESC),
  CONSTRAINT `job_position_ibfk_1` FOREIGN KEY (`enterprise_id`) REFERENCES `enterprise_info` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=102 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Job positions';
/*!40101 SET character_set_client = @saved_cs_client */;

