/*!40000 ALTER TABLE `job_position` DISABLE KEYS */;
INSERT INTO `job_position` VALUES (1,4,'2026届暑期实习-Golang后端开发工程师',3,'深入参与公司核心高并发业务的服务端开发工作。你将体验千万级DAU产品的技术架构，包括微服务拆分、缓存设计、数据库优化等。这是一个为期3个月的暑期技术夏令营，表现优异者可获得秋招SP/SSP提前批offer。','1. 2026届统招本科及以上学历，计算机相关专业；\n2. 扎实的计算机网络、操作系统、数据结构基础；\n3. 熟悉至少一门后端语言（Golang/Java/C++），有Golang经验加分；\n4. 具有较强的学习能力和抗压能力。','[\"Golang\", \"MySQL\", \"Redis\", \"高并发\", \"微服务\"]',200.00,300.00,'北京/全国','周一至周五 白天',9,'OPEN',351,13,'2026-03-07 09:44:19','2026-03-07 13:18:11','硕士','全职 3个月','[\"转正机会大\", \"大牛带队\", \"免费三餐\", \"住房补贴\"]','暑期实习'),(2,82,'2026届暑期实习-前端开发工程师（核心大前端）',3,'负责公司亿级用户规模的移动端及PC端Web业务开发。参与下一代前端架构演进，体验React/Vue3/TypeScript等前沿技术的工程化落地。我们提供完善的新人培养体系','1. 2026届本硕，有前端项目经验；\n2. 深入理解HTML/CSS/JS，熟悉前端主流框架及原理；\n3. 对前后端分离有深入理解；','[\"React\", \"Vue3\", \"TypeScript\", \"Webpack\"]',150.00,250.00,'北京/全国','周一至周五 白天',3,'OPEN',63,44,'2026-03-07 09:44:19','2026-03-07 13:18:11','不限','全职 3个月','[\"转正率80%\", \"六险一金\", \"弹性工作\"]','暑期实习'),(3,36,'2026届暑期实习-产品经理大拿训练营',2,'探索商业变现、用户增长的最前沿。你将独立负责一个子模块的迭代规划，从数据分析、用户调研到需求评审、项目验收，全链路体验产品经理的日常','1. 专业不限，极强的逻辑思维和数据分析能力；\n2. 同理心强，能敏锐洞察用户需求；','[\"产品设计\", \"数据分析\", \"Axure\", \"需求分析\"]',180.00,220.00,'北京/全国','周一至周五 白天',6,'OPEN',328,49,'2026-03-07 09:44:19','2026-03-07 13:18:11','不限','全职 3个月','[\"S级项目\", \"导师一对一\", \"快速晋升\"]','暑期实习'),(4,57,'2026届暑期实习-大模型算法工程师',3,'加入AI Lab，深入参与千亿参数大模型（LLM）的预训练、SFT微调、RLHF阶段。在海量算力平台探索前沿AI技术落地','1. 硕士及以上学历，人工智能/计算机方向；\n2. 熟练使用PyTorch，有顶会论文者优先；','[\"PyTorch\", \"LLM\", \"NLP\", \"深度学习\"]',350.00,500.00,'北京/全国','周一至周五 白天',1,'OPEN',321,42,'2026-03-07 09:44:19','2026-03-07 13:18:11','硕士','全职 3个月','[\"前沿技术\", \"海量算力\", \"顶薪转正\"]','暑期实习'),(5,26,'2026届暑期实习-商业分析师（战略投资部）',3,'参与行业研究、竞品分析，为高管的投资并购和战略布局提供数据支撑。这是一次全方位了解互联网下半场商业版图的机会','1. 顶尖海内外名校背景，金融/经济/管理类优先；\n2. 熟练掌握Excel高阶数据透视及SQL；','[\"商业分析\", \"SQL\", \"行研报告\", \"数据洞察\"]',250.00,400.00,'北京/全国','周一至周五 白天',10,'OPEN',433,8,'2026-03-07 09:44:19','2026-03-07 13:18:11','不限','全职 3个月','[\"直面高管\", \"深度行研\", \"精英圈层\"]','暑期实习'),(6,100,'【可远程】小红书图文运营实习生',3,'寻找网感极佳的Z世代！主要负责公司官方小红书账号的日常更新，包括选题策划、文案撰写、简单的图片排版。全程云办公，时间自由支配！','1. 5G冲浪选手，深谙小红书爆款文案套路；\n2. 会使用剪映、Canva、PS等基础排版工具；\n3. 每天能保证2-3小时输出时间，接受周末碎片化对接','[\"小红书运营\", \"文案撰写\", \"内容策划\", \"图片排版\"]',60.00,100.00,'北京/全国','周一至周五 白天',4,'OPEN',81,45,'2026-03-07 09:44:19','2026-03-07 13:18:11','不限','碎片化时间','[\"时间自由\", \"全票据报销\", \"无需打卡\", \"云端团队\"]','远程实习'),(7,46,'兼职远程-英法双语字幕翻译',3,'负责公司引入的海外纪录片、课程视频的本地化字幕翻译及校对工作。按照视频时长结算，多劳多得','1. 英语专八或同等水平，熟悉各类本土文化梗；\n2. 熟练使用ArcTime等字幕工具；','[\"字幕翻译\", \"英语专八\", \"本地化\", \"ArcTime\"]',80.00,150.00,'北京/全国','周一至周五 白天',8,'OPEN',111,47,'2026-03-07 09:44:19','2026-03-07 13:18:43','硕士','按件交付','[\"按件计费\", \"项目制\", \"时间灵活\"]','远程实习'),(8,27,'远程插画师（日系二次元风格）',4,'参与新研发二次元卡牌手游的立绘、CG等美术资产外包工作。根据主美需提供的设定独立完成上色及细化','1. 有成熟的二次元日系画风作品（投递需附带Pixiv等作品链接）；\n2. 熟悉人体结构、光影，具有良好的色彩感；','[\"原画设计\", \"二次元风格\", \"SAI/PS\", \"人物立绘\"]',150.00,300.00,'北京/全国','周一至周五 白天',8,'OPEN',118,41,'2026-03-07 09:44:19','2026-03-07 13:18:11','硕士','按画幅结算','[\"云端审稿\", \"接单自由\", \"版权署名\"]','远程实习'),(9,100,'【线上/远程】社群用户运营实习生',2,'负责付费用户微信社群的活跃引导、答疑解惑、活动统筹。你不需要来办公室，只要有一台手机和稳定的网速即可','1. 性格外向，喜欢在微信里聊天活跃气氛；\n2. 有极强的耐心，解答用户各种基础问题；','[\"社群运营\", \"用户维系\", \"活动策划\", \"沟通能力\"]',50.00,80.00,'北京/全国','周一至周五 白天',7,'OPEN',401,32,'2026-03-07 09:44:19','2026-03-07 13:18:11','不限','轮班制','[\"一部手机搞定\", \"月度奖金\", \"工作不设限\"]','远程实习'),(10,59,'海外电商独立站运营助手 (Remote)',3,'协助主管完成Shopify独立站的日常上新、商品描述本地化（英文）、竞品价格追踪。适合想要了解跨境电商又不想坐班的同学','1. 英语四六级以上，能无障碍浏览海外网站；\n2. 踏实细心，有较强的数据对比能力；','[\"跨境电商\", \"Shopify\", \"英语读写\", \"竞品分析\"]',70.00,120.00,'北京/全国','周一至周五 白天',8,'OPEN',310,36,'2026-03-07 09:44:19','2026-03-07 13:18:11','本科','日均3小时','[\"跨境风口\", \"老带新\", \"时间灵活\"]','远程实习'),(11,44,'2025/2026届-财务管培生实习（可转正）',3,'进入集团财务中心，轮岗于总账、AP/AR、资金管理、税务规划四大模块。这不仅是实习，更是寻找未来财务管理者的培养计划。','1. 25或26届统招本科/硕士，财务/会计类相关专业；\n2. 拥有CPA/ACCA通过部分科目者优先；\n3. 实习满4个月可提前发放秋招录用转正Offer。','[\"财务管理\", \"各类报表\", \"审计支持\", \"CPA优先\"]',150.00,200.00,'北京/全国','周一至周五 白天',8,'OPEN',185,0,'2026-03-07 09:44:19','2026-03-07 13:18:11','大专','每周4天 4个月','[\"管培生计划\", \"全留用指标\", \"年底分红制\", \"完善培训\"]','应届实习'),(12,67,'研发工程师（应届生留用专岗）- 新一代OS部',3,'加入国产智能汽车操作系统OS核心研发团队，参与车载底层通信架构、微内核进程调度的开发。实习期即被视为正式员工培养，共享内部最新技术文档。','1. 2025届毕业生，计算机/软件/通信工程专业；\n2. 精通C/C++，对Linux内核有深刻理解；\n3. 需要能够全职实习至毕业。','[\"C/C++\", \"Linux内核\", \"操作系统\", \"车载OS\"]',250.00,400.00,'北京/全国','周一至周五 白天',5,'OPEN',155,3,'2026-03-07 09:44:19','2026-03-07 13:18:11','硕士','每周5天 至毕业','[\"硬核技术\", \"100%转正\", \"购车补贴\", \"六险二金\"]','应届实习'),(13,3,'大客户销售（B2B SaaS）- 应届生直聘',5,'作为大客户经理储备军，你将负责国内Top500企业的线索挖掘与初步对接。百万年薪的起点，这绝不是一个打杂的岗位，而是真正的“拿业绩说话”。','1. 本科及以上，专业不限，极度渴望成功；\n2. 抗压能力强，有极强的自驱力和表达能力；','[\"TO B销售\", \"陌拜\", \"商务谈判\", \"SaaS软件\"]',150.00,200.00,'北京/全国','周一至周五 白天',6,'OPEN',233,7,'2026-03-07 09:44:19','2026-03-07 13:18:11','本科','每周5天 3个月','[\"高底薪高提成\", \"狼性文化\", \"销冠带教\"]','应届实习'),(14,41,'【可转正】海外市场PR营销实习生（出海业务）',3,'随着公司全球化战略加速，我们需要你协助对接欧美、东南亚的KOL/KOC，策划TikTok上的病毒营销事件，提升品牌国际影响力。','1. 海归留学生或具备海外生活经验者优先，英语听说读写接近母语水平；\n2. 深度TikTok重度用户，了解各类网红生态；','[\"海外PR\", \"KOL商务\", \"TikTok营销\", \"英语流利\"]',120.00,180.00,'北京/全国','周一至周五 白天',3,'OPEN',70,5,'2026-03-07 09:44:19','2026-03-07 13:18:11','大专','每周4天 5个月','[\"全球出海\", \"外企氛围\", \"直通转正\"]','应届实习'),(15,32,'人力资源实习生（招聘方向/直通秋招）',2,'深度参与公司级别的校招/社招全流程。从简历筛选、寻访(Mapping)、安排笔面试到后期的Offer沟通。你将站在HR视角看透招聘本质。','1. 2025届应届生，人力资源/心理学相关专业优先；\n2. 踏实细心，共情力强；\n3. 通过实习期考核100%留用进入HR总办。','[\"招聘交付\", \"简历筛选\", \"面试安排\", \"人才Mapping\"]',100.00,150.00,'北京/全国','周一至周五 白天',3,'OPEN',359,12,'2026-03-07 09:44:19','2026-03-07 13:18:11','不限','每周4天 3个月','[\"100%留用\", \"团队氛围好\", \"扁平管理\"]','应届实习'),(16,44,'Java业务开发实习生',1,'参与内部CRM系统的日常迭代开发','详情请参阅职位描述中的任职要求。','[\"执行力\", \"数据分析\"]',109.00,144.00,'北京/全国','周一至周五 白天',2,'OPEN',121,49,'2026-03-07 09:44:19','2026-03-07 13:15:51','本科','5天/周 3个月','[\"绩效奖金\", \"五险一金\", \"周末双休\", \"年底双薪\"]','综合'),(17,61,'人事行政实习生',3,'前台接待、物品采购及快递收发','详情请参阅职位描述中的任职要求。','[\"Vue\", \"MySQL\", \"React\", \"Spring Boot\"]',206.00,298.00,'北京/全国','周一至周五 白天',4,'OPEN',223,20,'2026-03-07 09:44:19','2026-03-07 13:15:51','不限','5天/周 3个月','[\"免费三餐\", \"租房补贴\", \"交通补助\", \"定期团建\"]','综合'),(18,8,'测试实习生 (QA)',6,'编写测试用例，执行手动及自动化测试','详情请参阅职位描述中的任职要求。','[\"PPT\", \"抗压能力\", \"Figma\"]',147.00,181.00,'北京/全国','周一至周五 白天',10,'OPEN',437,32,'2026-03-07 09:44:19','2026-03-07 13:15:51','不限','5天/周 6个月','[\"交通补助\", \"弹性工作\", \"扁平管理\", \"不打卡\"]','综合'),(19,54,'Python开发实习生 (编号19)',3,'职位描述\n团队介绍：我们是一支年轻且充满活力的团队，核心成员来自一线互联网大厂，致力于为用户提供创新的产品体验。团队氛围轻松活跃，有着完善的培养体系，导师一对一帮带，帮助实习生快速成长。在这里你不仅能接触到核心业务，还能参与到产品从0到1的建设过程。\n\n工作职责：\n1、协助团队完成日常项目跟进与落地，确保进度与质量；\n2、对接内部各业务部门，协调资源，推进跨团队合作；\n3、参与相关业务数据的统计分析，输出数据报告并提出优化建议；\n4、完成主管交办的其他相关支持性工作，如会议纪要、文档整理等。\n\n任职要求：\n1、统招本科及以上学历在读，专业不限（相关专业优先）；\n2、具备良好的逻辑思维能力和沟通表达能力，工作细致耐心；\n3、熟练使用常用办公软件（Word/Excel/PPT等）；\n4、具备较强的抗压能力和责任心，学习能力强，能快速融入团队；\n5、每周可实习4天以上，连续实习3个月以上者优先考​​虑。\n','详情请参阅职位描述中的任职要求。','[\"HTML/CSS\", \"JavaScript\", \"Go\", \"Python\"]',156.00,238.00,'北京','周一至周五 白天',7,'OPEN',159,2,'2026-03-07 09:44:19','2026-03-07 09:44:19','大专','5天/周 6个月','[\"免费三餐\", \"租房补贴\", \"交通补助\", \"定期团建\"]','综合'),(20,15,'运维实习生 (编号20)',3,'职位描述\nByteIntern：面向2026届毕业生（2025年9月-2026年8月期间毕业），为符合岗位要求的同学提供转正机会。\n团队介绍：产品覆盖今日头条、头条极速版等各类产品，为上亿用户持续提供优质的资讯、视频等服务。我们通过建立良好的内容生态，鼓励优质的原创内容，为创作者提供优质的服务和创作体验，促进创作和交流，同时我们致力于通过尽可能丰富的内容体裁和尽可能多的分发方式，连接人与信息，丰富大家的精神生活，让人们看到更大的世界。\n\n1、主要负责客户端/服务端产品质量相关或业务线测试与工具开发工作；\n2、深度参与产品研发项目，协同产品和研发团队高质量交付产品；\n3、日常项目线下测试与线上质量分析；\n4、参与质量体系规划和建设；\n5、参与开发效率工具和保证技术项目质量。\n\n职位要求\n1、2026届本科及以上学历在读，计算机等相关专业；\n2、热爱互联网，对互联网相关业务和技术充满好奇及热情；\n3、具备快速的产品及业务学习能力、敏捷而周到的逻辑思维能力以及良好的沟通协作能力；\n4、有移动互联网测试经验，有自动化或白盒测试经验优先考虑；\n5、了解常用客户端、服务端开发及前沿技术，如自动化框架、压测工具、大数据处理，AI大模型等优先；\n6、每周至少工作4天，实习时间3个月及以上。\n','详情请参阅职位描述中的任职要求。','[\"Go\", \"Node.js\", \"JavaScript\"]',162.00,280.00,'全国','周一至周五 白天',7,'OPEN',86,24,'2026-03-07 09:44:19','2026-03-07 09:44:19','不限','4天/周 3个月','[\"免费三餐\", \"租房补贴\", \"交通补助\", \"定期团建\"]','综合'),(21,70,'前端开发实习生 (编号21)',3,'职位描述\n团队介绍：我们是一支年轻且充满活力的团队，核心成员来自一线互联网大厂，致力于为用户提供创新的产品体验。团队氛围轻松活跃，有着完善的培养体系，导师一对一帮带，帮助实习生快速成长。在这里你不仅能接触到核心业务，还能参与到产品从0到1的建设过程。\n\n工作职责：\n1、协助团队完成日常项目跟进与落地，确保进度与质量；\n2、对接内部各业务部门，协调资源，推进跨团队合作；\n3、参与相关业务数据的统计分析，输出数据报告并提出优化建议；\n4、完成主管交办的其他相关支持性工作，如会议纪要、文档整理等。\n\n任职要求：\n1、统招本科及以上学历在读，专业不限（相关专业优先）；\n2、具备良好的逻辑思维能力和沟通