DROP TABLE IF EXISTS `match_score`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `match_score` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `student_id` bigint NOT NULL COMMENT 'FK to student_profile',
  `job_id` bigint NOT NULL COMMENT 'FK to job_position',
  `total_score` decimal(5,2) NOT NULL COMMENT 'Overall match score 0-100',
  `skill_score` decimal(5,2) DEFAULT '0.00' COMMENT 'Skill match score',
  `salary_score` decimal(5,2) DEFAULT '0.00' COMMENT 'Salary match score',
  `location_score` decimal(5,2) DEFAULT '0.00' COMMENT 'Location match score',
  `schedule_score` decimal(5,2) DEFAULT '0.00' COMMENT 'Schedule match score',
  `computed_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_student_job` (`student_id`,`job_id`),
  KEY `job_id` (`job_id`),
  KEY `idx_total_score` (`total_score` DESC),
  CONSTRAINT `match_score_ibfk_1` FOREIGN KEY (`student_id`) REFERENCES `student_profile` (`id`) ON DELETE CASCADE,
  CONSTRAINT `match_score_ibfk_2` FOREIGN KEY (`job_id`) REFERENCES `job_position` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1044 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Pre-computed matching scores';
/*!40101 SET character_set_client = @saved_cs_client */;

