--
-- Table structure for table `student_profile`
--

DROP TABLE IF EXISTS `student_profile`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_profile` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT 'FK to sys_user',
  `university` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'University name',
  `major` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Major / Discipline',
  `education_level` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Degree level: BACHELOR, MASTER, PHD',
  `enrollment_year` int DEFAULT NULL COMMENT 'Enrollment year',
  `skills` json DEFAULT NULL COMMENT 'Skill tags as JSON array',
  `self_intro` text COLLATE utf8mb4_unicode_ci COMMENT 'Self introduction',
  `expected_salary_min` decimal(10,2) DEFAULT NULL COMMENT 'Min expected salary (per hour)',
  `expected_salary_max` decimal(10,2) DEFAULT NULL COMMENT 'Max expected salary (per hour)',
  `expected_location` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Preferred work locations',
  `available_schedule` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Available time slots',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `notify_application_status` bit(1) DEFAULT NULL,
  `notify_interview` bit(1) DEFAULT NULL,
  `notify_message_sound` bit(1) DEFAULT NULL,
  `notify_new_job` bit(1) DEFAULT NULL,
  `notify_new_message` bit(1) DEFAULT NULL,
  `notify_promotion` bit(1) DEFAULT NULL,
  `notify_system_announcement` bit(1) DEFAULT NULL,
  `privacy_resume_open` bit(1) DEFAULT NULL,
  `privacy_show_contact` bit(1) DEFAULT NULL,
  `privacy_show_last_active` bit(1) DEFAULT NULL,
  `privacy_show_name` bit(1) DEFAULT NULL,
  `privacy_show_online` bit(1) DEFAULT NULL,
  `resume_attachments` json DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `user_id` (`user_id`),
  CONSTRAINT `student_profile_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=38 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Student profiles / resumes';
/*!40101 SET character_set_client = @saved_cs_client */;

